      END_STATE();
    case 112:
      ACCEPT_TOKEN(sym_char_literal);
      END_STATE();
    case 113:
      ACCEPT_TOKEN(sym_line_comment);
      if (lookahead == '{' ||
          lookahead == '}') ADVANCE(114);
      if (lookahead != 0 &&
          lookahead != '\n') ADVANCE(113);
      END_STATE();
    case 114:
      ACCEPT_TOKEN(sym_line_comment);
